'use client';

import { useState, useRef, useMemo } from 'react';
import Image from 'next/image';
import { motion } from 'framer-motion';
import { Onest } from 'next/font/google';
import { Roboto_Mono } from 'next/font/google';

const onest = Onest({ subsets: ['latin'], weight: ['100', '300', '500', '700'] });
const robotoMono = Roboto_Mono({ subsets: ['latin'], weight: ['100', '200', '300', '500', '700'] });

// Shared Interfaces
interface Tag { id: string; name: string; }
export interface LibraryItem {
  id: string;
  collectionId: string;
  title: string;
  category: string;
  cover_image: string;
  properties: Record<string, any>;
  expand?: { tags?: Tag[] };
}

function getImageUrl(collectionId: string, recordId: string, fileName: string) {
  return `http://127.0.0.1:8090/api/files/${collectionId}/${recordId}/${fileName}`;
}

export default function LibraryGrid({ items }: { items: LibraryItem[] }) {
  const [selectedItem, setSelectedItem] = useState<LibraryItem | null>(null);
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [activeCategories, setActiveCategories] = useState<string[]>([]);
  const [activeTags, setActiveTags] = useState<string[]>([]);
  const boundaryRef = useRef<HTMLDivElement>(null);

  const uniqueCategories = Array.from(new Set(items.map(item => item.category)));
  const uniqueTags = Array.from(new Set(items.flatMap(item => item.expand?.tags?.map(t => t.name) || [])));

  const filteredItems = useMemo(() => {
    return items.filter((item) => {
      // If categories are selected, the item must match one of them
      const categoryMatch = activeCategories.length === 0 || activeCategories.includes(item.category);
      // If tags are selected, the item must possess at least one of them
      const itemTags = item.expand?.tags?.map(t => t.name) || [];
      const tagMatch = activeTags.length === 0 || activeTags.some(t => itemTags.includes(t));
      
      return categoryMatch && tagMatch;
    });
  }, [items, activeCategories, activeTags]);

  // Artificially tile the items to create a massive repeating grid for the "infinite" feel
  // We duplicate the array 16 times to fill a large draggable plane
  const tiledItems = Array(16).fill(items).flat().map((item, index) => ({
    ...item,
    uniqueGridId: `${item.id}-${index}` // Ensure React keys remain unique
  }));

  const toggleFilter = (value: string, currentArray: string[], setter: React.Dispatch<React.SetStateAction<string[]>>) => {
    if (currentArray.includes(value)) {
      setter(currentArray.filter(v => v !== value));
    } else {
      setter([...currentArray, value]);
    }
  };

  return (
    <div className="relative w-screen h-screen overflow-hidden bg-white text-black font-sans selection:bg-black selection:text-white">
      
    {/* --- FLOATING NAVBAR --- */}
    <header className="fixed top-0 left-0 w-full flex justify-between items-center px-8 py-6 z-50 pointer-events-none">
        {/* Logo */}
        {/* A. The Logo Graphic (Replace this SVG with an <Image /> later if you have a PNG) */}
        <div className="flex items-center gap-3">
          <Image src="/logo-black.png" alt="Logo" width={32} height={32} className="pointer-events-auto" />
          <span className={`${onest.className} text-3xl tracking-[-0.075em] pt-1`}>
            VisualLibrary
          </span>
        </div>
        
        <div className="flex flex-col items-end gap-2 pointer-events-auto">
            <div className="flex items-center gap-6">
            <button 
              onClick={() => setIsFilterOpen(!isFilterOpen)}
              className={`flex items-center gap-2 text-sm font-medium hover:opacity-50 transition-opacity ${isFilterOpen ? 'opacity-50' : ''}`}
            >
                <span className={`${onest.className} text-sm tracking-[-0.5 em] font-medium pt-1`}>
                    Filter 
                </span>
                <svg width="10" height="6" viewBox="0 0 10 6" fill="none" xmlns="http://www.w3.org/2000/svg">
                    <path d="M1 1L5 5L9 1" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
            </button>
            <button className="hover:opacity-50 transition-opacity">
                <span className={`${onest.className} text-sm tracking-[-0.5 em] font-medium pt-1`}>
                    Search 
                </span>
            </button>
            </div>

            {/* --- FILTER DROPDOWN UI --- */}
          {isFilterOpen && (
            <motion.div 
              initial={{ opacity: 0, y: -10 }}
              animate={{ opacity: 1, y: 0 }}
              className="mt-4 w-72 bg-white border border-neutral-200 shadow-2xl p-6 flex flex-col gap-6"
            >
              {/* Categories Section */}
              <div>
                <h3 className="text-[10px] uppercase tracking-widest text-neutral-400 mb-3 border-b border-neutral-100 pb-2">Categories</h3>
                <div className="flex flex-wrap gap-2">
                  {uniqueCategories.map(cat => (
                    <button 
                      key={cat}
                      onClick={() => toggleFilter(cat, activeCategories, setActiveCategories)}
                      className={`px-2 py-1 text-xs border uppercase tracking-wider transition-colors ${activeCategories.includes(cat) ? 'bg-black text-white border-black' : 'bg-transparent text-neutral-600 border-neutral-200 hover:border-neutral-400'}`}
                    >
                      {cat.replace('_', ' ')}
                    </button>
                  ))}
                </div>
              </div>

              {/* Tags Section */}
              {uniqueTags.length > 0 && (
                <div>
                  <h3 className="text-[10px] uppercase tracking-widest text-neutral-400 mb-3 border-b border-neutral-100 pb-2">Parameters</h3>
                  <div className="flex flex-wrap gap-2">
                    {uniqueTags.map(tag => (
                      <button 
                        key={tag}
                        onClick={() => toggleFilter(tag, activeTags, setActiveTags)}
                        className={`px-2 py-1 text-xs border uppercase tracking-wider transition-colors ${activeTags.includes(tag) ? 'bg-neutral-800 text-white border-neutral-800' : 'bg-transparent text-neutral-600 border-neutral-200 hover:border-neutral-400'}`}
                      >
                        {tag}
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </motion.div>
          )}
        </div>
    </header>

      {/* --- THE DRAGGABLE SPATIAL CANVAS --- */}
      {/* This boundary restricts how far you can drag the plane */}
      <div ref={boundaryRef} className="absolute inset-0 z-0">
        <motion.div
          drag
          dragConstraints={boundaryRef}
          dragElastic={0.1}
          whileDrag={{ cursor: "grabbing" }}
          // Create a massive plane larger than the viewport
          className="w-[300vw] h-[300vh] sm:w-[200vw] sm:h-[200vh] absolute top-[-50vh] left-[-50vw] cursor-grab flex flex-wrap content-start p-32 gap-8 md:gap-16"
        >
          {tiledItems.length === 0 ? (
             <div className="w-full h-[50vh] flex items-center justify-center text-neutral-400 text-sm tracking-widest uppercase">
                No items match the current parameters.
             </div>
          ) : (
            tiledItems.map((item) => (
            <div 
              key={item.uniqueGridId} 
              onDoubleClick={() => setSelectedItem(item)}
              // Width calculations to create a responsive grid on a massive plane
              // Crucial: aspect-square enforces the 1:1 ratio
              className="relative w-[40vw] sm:w-[20vw] lg:w-[12vw] aspect-square bg-neutral-200 group overflow-hidden transition-transform duration-300 hover:scale-[1.02] shadow-sm hover:shadow-xl"
            >
              {item.cover_image ? (
                <Image
                  src={getImageUrl(item.collectionId, item.id, item.cover_image)}
                  alt={item.title}
                  fill
                  unoptimized
                  className="object-cover opacity-90 group-hover:grayscale-0 group-hover:opacity-100 transition-all duration-500 pointer-events-none"
                />
              ) : (
                <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                  <svg className="w-8 h-8 text-neutral-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                  </svg>
                </div>
              )}
            </div>
            ))
          )}
        </motion.div>
      </div>

      {/* --- FLOATING FOOTER --- */}
      <footer className="fixed bottom-0 left-0 w-full flex flex-col sm:flex-row justify-between items-center px-8 py-6 z-50 text-xs font-bold pointer-events-none bg-gradient-to-t from-white/80 to-transparent">
        <div className="pointer-events-auto mb-4 sm:mb-0">
            <span className={`${onest.className} text-sm tracking-[-0.5 em] font-medium pt-1`}>
                <span className={`${robotoMono.className} text-sm tracking-[-0.5 em] font-extralight pt-1`}>studiobluprnt</span>'s VisualLibrary            
            </span>
        </div>
        <div className="flex gap-8 pointer-events-auto">
            <button className="hover:opacity-50 transition-opacity">
                <span className={`${onest.className} text-sm tracking-[-0.5 em] font-medium pt-1`}>
                    Return home
                </span>
            </button>
            <button className="hover:opacity-50 transition-opacity">
                <span className={`${onest.className} text-sm tracking-[-0.5 em] font-medium pt-1`}>
                    About us
                </span>
            </button>
        </div>
      </footer>

      {/* --- MODAL OVERLAY (Kept from previous iteration) --- */}
      {selectedItem && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-white/90 backdrop-blur-md p-4" onClick={() => setSelectedItem(null)}>
           {/* Modal Sub-Window code remains unchanged... */}
           <div className="bg-white border border-neutral-200 shadow-2xl p-8 max-w-4xl w-full flex flex-col md:flex-row h-[80vh]" onClick={e => e.stopPropagation()}>
              <div className="w-full md:w-1/2 relative bg-neutral-100 border-r border-neutral-200">
                 {selectedItem.cover_image && (
                   <Image src={getImageUrl(selectedItem.collectionId, selectedItem.id, selectedItem.cover_image)} alt={selectedItem.title} fill unoptimized className="object-cover" />
                 )}
              </div>
              <div className="w-full md:w-1/2 p-8 flex flex-col overflow-y-auto font-mono">
                <div className="flex justify-between items-start border-b border-neutral-200 pb-4 mb-6">
                  <div>
                    <h2 className="text-2xl font-bold tracking-tight mb-2">{selectedItem.title}</h2>
                    <span className="px-2 py-1 text-[10px] bg-black text-white uppercase tracking-widest">{selectedItem.category.replace('_', ' ')}</span>
                  </div>
                  <button onClick={() => setSelectedItem(null)} className="text-neutral-400 hover:text-black transition-colors">[ X ]</button>
                </div>
                <div className="flex flex-wrap gap-2 mb-8">
                  {selectedItem.expand?.tags?.map((tag) => (
                    <span key={tag.id} className="px-2 py-1 text-[10px] border border-neutral-300 text-neutral-600 uppercase tracking-wider">{tag.name}</span>
                  ))}
                </div>
                <div className="flex-grow">
                   <h3 className="text-xs text-neutral-400 mb-3 uppercase tracking-widest">Node Parameters</h3>
                   <pre className="text-[10px] leading-relaxed bg-neutral-50 text-neutral-800 p-4 border border-neutral-200 overflow-x-auto">{JSON.stringify(selectedItem.properties, null, 2)}</pre>
                </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
}